-- ============================================================
-- Aurora 4x 日本人指揮官 姓漢字化SQL
-- DIM_CommanderNames NameThemeID=8（日本語テーマ）の
-- FamilyName エントリをローマ字から漢字に置き換えます
-- 元の件数（973件）を維持し、最後に眞鍋を追加（計973件）
-- 何度実行しても同じ結果になります（冪等性）
-- ============================================================

-- 誤って作成したThemeID=706の船名テーマを削除
DELETE FROM DIM_NamingTheme WHERE NameThemeID=706;
DELETE FROM DIM_NamingThemeTypes WHERE ThemeID=706;

-- 既存の姓エントリを削除してから漢字で再挿入
DELETE FROM DIM_CommanderNames WHERE NameThemeID=8 AND FamilyName=1;


